async (page) => {
  // Focus the canvas first, then use keyboard to walk into rat
  // Rat is at (174, 157), player at (178, 160) - need to go NW (west = A, north = W)

  // Click canvas to ensure focus
  await page.evaluate(() => {
    document.getElementById('canvas').focus();
    // Also try to dispatch a focus event
    document.getElementById('canvas').dispatchEvent(new Event('focus'));
  });
  await page.waitForTimeout(200);

  // Press keyboard to move toward rat
  // Need to go west (A key) and north (W key)
  // Rat is 4 tiles west, 3 tiles north
  for (let i = 0; i < 4; i++) {
    await page.keyboard.press('ArrowLeft');
    await page.waitForTimeout(300);
  }
  for (let i = 0; i < 3; i++) {
    await page.keyboard.press('ArrowUp');
    await page.waitForTimeout(300);
  }

  await page.waitForTimeout(2000);
  await page.screenshot({ path: '/tmp/kaetram_agent_1/state/screenshot.png', type: 'png' });
  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  const parsed = JSON.parse(state);
  return JSON.stringify({ pos: parsed.player_position, hp: parsed.player_stats.hp, xp: parsed.last_xp_event, combat: parsed.last_combat, exp: parsed.player_stats.experience });
}

async (page) => {
  const pressKey = async (key, code) => {
    await page.evaluate(({key, code}) => {
      document.dispatchEvent(new KeyboardEvent('keydown', { key, code, bubbles: true }));
      setTimeout(() => document.dispatchEvent(new KeyboardEvent('keyup', { key, code, bubbles: true })), 100);
    }, {key, code});
    await page.waitForTimeout(600);
  };

  // Walk west into rat at (174, 157)
